def mergeKLists(lists):
    if not lists: return None
    result = lists[0]
    for i in range(1, len(lists)):
        result = mergeTwoLists(result, lists[i])
    return result

def mergeTwoLists(l1, l2):
    dummy = ListNode(0)
    current = dummy
    while l1 and l2:
        if l1.val <= l2.val:
            current.next = l1
            l1 = l1.next
        else:
            current.next = l2
            l2 = l2.next
        current = current.next
    current.next = l1 if l1 else l2
    return dummy.next

result = lists[0] if lists else None
for i in range(1, len(lists)):
    result = mergeTwoLists(result, lists[i])

class ListNode:
    def __init__(self, val=0, next=None):
        self.val = val
        self.next = next

